                    if nums[left] > val - 1:
                        total += val - 1
                    else:
                        total += nums[left]
                if right < n - 1:
                    right += 1
                    if nums[right] > val - 1:
                        total += val - 1
                    else:
                        total += nums[right]
                if total > maxSum:
                    return False
            return True

        nums = [1] * n
        left, right = 1, maxSum
        while left <= right:
            mid = (left + right) // 2
            nums[index] = mid
            if possible(mid):
                left = mid + 1
            else:
                right = mid - 1
